import { h, Signal } from '@tu-lang/runtime'

export const frontmatter = new Signal.State({})
export const Page = () => h("div", {}, [h("$static", {}, [], "<article class=\"tu-markdown\"><h1>Tu × Tailwind</h1>\n<p>Tu compiles <code>class:</code> props to standard HTML <code>class</code> attributes, so any utility-CSS framework that scans content for class strings works out of the box. Tailwind v4’s <code>@source</code> directive is all you need.</p>\n<h2>Setup</h2>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#B392F0\">pnpm</span><span style=\"color:#9ECBFF\"> add</span><span style=\"color:#79B8FF\"> -D</span><span style=\"color:#9ECBFF\"> tailwindcss</span><span style=\"color:#9ECBFF\"> @tailwindcss/vite</span></span>\n<span class=\"line\"></span></code></pre>\n<p>In your Vite config:</p>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#F97583\">import</span><span style=\"color:#E1E4E8\"> tailwindcss </span><span style=\"color:#F97583\">from</span><span style=\"color:#9ECBFF\"> '@tailwindcss/vite'</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">import</span><span style=\"color:#E1E4E8\"> tu </span><span style=\"color:#F97583\">from</span><span style=\"color:#9ECBFF\"> '@tu-lang/vite'</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">import</span><span style=\"color:#E1E4E8\"> { defineConfig } </span><span style=\"color:#F97583\">from</span><span style=\"color:#9ECBFF\"> 'vite'</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">export</span><span style=\"color:#F97583\"> default</span><span style=\"color:#B392F0\"> defineConfig</span><span style=\"color:#E1E4E8\">({</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">  plugins: [</span><span style=\"color:#B392F0\">tu</span><span style=\"color:#E1E4E8\">(), </span><span style=\"color:#B392F0\">tailwindcss</span><span style=\"color:#E1E4E8\">()],</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">})</span></span>\n<span class=\"line\"></span></code></pre>\n<p>In your entry CSS:</p>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#F97583\">@import</span><span style=\"color:#9ECBFF\"> \"tailwindcss\"</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">@source</span><span style=\"color:#E1E4E8\"> \"./**/*.tu\";</span></span>\n<span class=\"line\"></span></code></pre>\n<p>That’s it. No PostCSS config, no purge list maintenance, no framework-specific plugin. Tu emits standard HTML strings that Tailwind’s content scanner picks up.</p>\n<h2>Use</h2>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#F97583\">export</span><span style=\"color:#F97583\"> let</span><span style=\"color:#B392F0\"> App</span><span style=\"color:#F97583\"> =</span><span style=\"color:#E1E4E8\"> () </span><span style=\"color:#F97583\">=></span><span style=\"color:#85E89D\"> div</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#B392F0\">class</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#9ECBFF\">\"max-w-2xl mx-auto p-8 space-y-6\"</span><span style=\"color:#E1E4E8\">) {</span></span>\n<span class=\"line\"><span style=\"color:#85E89D\">  header</span><span style=\"color:#E1E4E8\"> {</span></span>\n<span class=\"line\"><span style=\"color:#85E89D\">    h1</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#B392F0\">class</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#9ECBFF\">\"text-4xl font-bold tracking-tight bg-gradient-to-r from-indigo-400 to-purple-400 bg-clip-text text-transparent\"</span><span style=\"color:#E1E4E8\">) {</span></span>\n<span class=\"line\"><span style=\"color:#9ECBFF\">      \"Tu × Tailwind\"</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">  }</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#85E89D\">  button</span><span style=\"color:#E1E4E8\">(</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">    class</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#9ECBFF\">\"px-4 py-2 rounded-lg bg-indigo-500 hover:bg-indigo-400 text-white font-medium transition-colors\"</span><span style=\"color:#E1E4E8\">,</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">    onClick</span><span style=\"color:#E1E4E8\">: () </span><span style=\"color:#F97583\">=></span><span style=\"color:#E1E4E8\"> count </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> count </span><span style=\"color:#F97583\">+</span><span style=\"color:#79B8FF\"> 1</span><span style=\"color:#E1E4E8\">,</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">  ) { </span><span style=\"color:#9ECBFF\">\"+1\"</span><span style=\"color:#E1E4E8\"> }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span></code></pre>\n<h2>Coexistence with <code>style { … }</code> blocks</h2>\n<p>Tailwind utilities and Tu’s scoped style blocks compose freely on the same element:</p>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#E1E4E8\">.</span><span style=\"color:#85E89D\">badge</span><span style=\"color:#E1E4E8\">() {</span></span>\n<span class=\"line\"><span style=\"color:#85E89D\">  span</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#B392F0\">class</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#9ECBFF\">\"inline-flex items-center gap-2\"</span><span style=\"color:#E1E4E8\">) {</span></span>\n<span class=\"line\"><span style=\"color:#85E89D\">    span</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#B392F0\">class</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#9ECBFF\">\"w-2 h-2 rounded-full bg-emerald-400 animate-pulse\"</span><span style=\"color:#E1E4E8\">)</span></span>\n<span class=\"line\"><span style=\"color:#9ECBFF\">    \"Live reactive\"</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">  }</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">  style</span><span style=\"color:#E1E4E8\"> {</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">    .badge</span><span style=\"color:#E1E4E8\"> {</span></span>\n<span class=\"line\"><span style=\"color:#79B8FF\">      display</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">inline-block</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#79B8FF\">      padding</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">0.25</span><span style=\"color:#F97583\">rem</span><span style=\"color:#79B8FF\"> 0.75</span><span style=\"color:#F97583\">rem</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#79B8FF\">      border</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">1</span><span style=\"color:#F97583\">px</span><span style=\"color:#79B8FF\"> solid</span><span style=\"color:#79B8FF\"> rgba</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#79B8FF\">110</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#79B8FF\">231</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#79B8FF\">183</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#79B8FF\">0.3</span><span style=\"color:#E1E4E8\">);</span></span>\n<span class=\"line\"><span style=\"color:#79B8FF\">      border-radius</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">9999</span><span style=\"color:#F97583\">px</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">  }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span></code></pre>\n<p>The <code>.badge</code> ClassRef gets the per-component hash (M5/F dual-class injection), Tailwind utilities get included by the content scanner, and they sit side by side on the rendered element.</p>\n<h2>With tu-xing</h2>\n<p>If you want <strong>theme tokens + ready-made primitives</strong>, layer <code>@tu-lang/tu-xing</code> on top — it’s Tailwind-driven internally and exposes HSL CSS variables for retheming. See <a href=\"./tu-xing\">tu-xing</a> for the install steps.</p>\n<h2>Live demo</h2>\n<p>Run <code>pnpm --filter tu-playground dev</code>, switch to the <strong>Tailwind</strong> demo in the sidebar.</p>\n</article>")])
